module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
) (
    input  wire                 wclk,
    input  wire                 wenc,
    input  wire [WIDTH-1:0]     wdata,
    input  wire                 rclk,
    input  wire                 renc,
    output wire [WIDTH-1:0]     rdata,
    output wire                 wfull,
    output wire                 rempty
);

localparam ADDR_WIDTH = $clog2(DEPTH);

reg [ADDR_WIDTH-1:0] wp, rp;
reg [WIDTH-1:0] ram[DEPTH-1:0];
reg [ADDR_WIDTH:0] wc, rc;

assign wfull  = (wc == {~rp, wp});
assign rempty = (rc == wc);

always @(posedge wclk) begin
    if (wenc && !wfull) begin
        ram[wp] <= wdata;
        wp <= wp + 1'b1;
    end
end

always @(posedge rclk) begin
    if (renc && !rempty) begin
        rp <= rp + 1'b1;
    end
end

always @(posedge wclk) begin
    wc <= wp;
end

always @(posedge rclk) begin
    rc <= rp;
end

assign rdata = ram[rp];

endmodule
